# Category: datastore_security

import psycopg2
import sys

def install_extension(db_name, db_user, db_password, db_host, db_port, extension_name):
    conn = None
    try:
        conn = psycopg2.connect(
            dbname=db_name,
            user=db_user,
            password=db_password,
            host=db_host,
            port=db_port
        )
        cur = conn.cursor()

        print(f"Attempting to create extension: {extension_name}...")
        cur.execute(f"CREATE EXTENSION IF NOT EXISTS {extension_name};")
        conn.commit()
        print(f"Extension '{extension_name}' created successfully.")

    except psycopg2.errors.InsufficientPrivilege as e:
        print(f"Error: Insufficient privileges to create extension '{extension_name}'.")
        print("Please ensure your database user has SUPERUSER or appropriate privileges.")
        print(f"Details: {e}")
    except psycopg2.errors.UndefinedFile as e:
        print(f"Error: Extension '{extension_name}' is not available or not found on the server.")
        print("Please ensure the extension's files are correctly installed in PostgreSQL's share directory.")
        print(f"Details: {e}")
    except psycopg2.Error as e:
        print(f"Database error during extension creation: {e}")
        if conn:
            conn.rollback()
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
    finally:
        if conn:
            conn.close()

if __name__ == '__main__':
    if len(sys.argv) < 6:
        print("Usage: python pg_admin_tool.py <db_name> <db_user> <db_password> <db_host> <db_port>")
        sys.exit(1)

    db_name_arg = sys.argv[1]
    db_user_arg = sys.argv[2]
    db_password_arg = sys.argv[3]
    db_host_arg = sys.argv[4]
    db_port_arg = sys.argv[5]

    print("\nPostgreSQL Extension Management Tool")
    print("-----------------------------------")
    print(f"Connecting to: {db_user_arg}@{db_host_arg}:{db_port_arg}/{db_name_arg}")

    while True:
        extension_to_install = input("\nEnter extension name to install (e.g., plpythonu, pgcrypto, hstore, or 'exit' to quit): ").strip()
        if extension_to_install.lower() == 'exit':
            break
        if not extension_to_install:
            print("Extension name cannot be empty. Please try again.")
            continue

        install_extension(db_name_arg, db_user_arg, db_password_arg, db_host_arg, db_port_arg, extension_to_install)

    print("\nExiting tool.")